 // ─── Graph in JavaScript ────────────────────────────────────────────────────
//
// Represented as an adjacency list — a Map where each key is a vertex
// and the value is an array of neighboring vertices.
// O(V+E) space. Best for sparse graphs (most real-world graphs).

class Graph {
  constructor(directed = false) {
    this.adjList  = new Map();
    this.directed = directed;
    }
    // ── O(1) — Add vertex ────────────────────────────────────────────────────
  addVertex(v) {
    if (!this.adjList.has(v)) this.adjList.set(v,
        []);
    }
    // ── O(V+E) — Remove vertex + all edges referencing it ───────────────────
  removeVertex(v) {
    this.adjList.delete(v);
    for (const [
            , neighbors
        ] of this.adjList) {
      const idx = neighbors.indexOf(v);
      if (idx !== -1) neighbors.splice(idx,
            1);
        }
    }
    // ── O(1) — Add edge ──────────────────────────────────────────────────────
  addEdge(u, v) {
    this.adjList.get(u)?.push(v);
    if (!this.directed) this.adjList.get(v)?.push(u);
    }
    // ── O(degree) — Remove edge ──────────────────────────────────────────────
  removeEdge(u, v) {
    this.adjList.set(u, (this.adjList.get(u) || []).filter(n => n !== v));
    if (!this.directed)
      this.adjList.set(v, (this.adjList.get(v) || []).filter(n => n !== u));
    }
    // ── O(degree) — Check if edge exists ────────────────────────────────────
  hasEdge(u, v) {
    return (this.adjList.get(u) || []).includes(v);
    }
    // ── O(1) — Get neighbors ─────────────────────────────────────────────────
  neighbors(v) {
    return this.adjList.get(v) || [];
    }
    // ── O(V+E) — BFS from start vertex ──────────────────────────────────────
  bfs(start) {
    const visited = new Set([start
        ]);
    const queue   = [start
        ];
    const order   = [];

    while (queue.length) {
      const curr = queue.shift(); // O(1) amortized with proper queue
      order.push(curr);
      for (const neighbor of this.neighbors(curr)) {
        if (!visited.has(neighbor)) {
          visited.add(neighbor);
          queue.push(neighbor);
                }
            }
        }
    return order; // level-by-level traversal
    }
    // ── O(V+E) — DFS from start vertex (iterative) ──────────────────────────
  dfs(start) {
    const visited = new Set();
    const stack   = [start
        ];
    const order   = [];

    while (stack.length) {
      const curr = stack.pop();
      if (visited.has(curr)) continue;
      visited.add(curr);
      order.push(curr);
      // Push neighbors in reverse so left-to-right processing order
      for (const neighbor of [...this.neighbors(curr)
            ].reverse()) {
        if (!visited.has(neighbor)) stack.push(neighbor);
            }
        }
    return order;
    }
}
// ── Usage ─────────────────────────────────────────────────────────────────
const g = new Graph(false); // undirected
['A','B','C','D','E'
].forEach(v => g.addVertex(v));
g.addEdge('A','B'); g.addEdge('A','C');
g.addEdge('B','D'); g.addEdge('C','E');

console.log(g.bfs('A')); // ['A','B','C','D','E']
console.log(g.dfs('A')); // ['A','B','D','C','E']
console.log(g.hasEdge('A','B')); // true
console.log(g.neighbors('A')); // ['B','C']

# ─── Graph in Python ────────────────────────────────────────────────────────
#
# Python's dict (hash map) is the natural adjacency list container.
# collections.defaultdict(list) auto-creates empty lists for new keys.

from collections import defaultdict, deque

class Graph:
    def __init__(self, directed=False):
        self.adj      = defaultdict(list)
        self.directed = directed
        self.vertices = set()

    # ── O(1) — Add vertex ────────────────────────────────────────────────
    def add_vertex(self, v):
        self.vertices.add(v)
        _ = self.adj[v
]   # ensure key exists

    # ── O(V+E) — Remove vertex + all edges referencing it ───────────────
    def remove_vertex(self, v):
        self.vertices.discard(v)
        del self.adj[v
]
        for neighbors in self.adj.values():
            if v in neighbors:
                neighbors.remove(v)

    # ── O(1) — Add edge ──────────────────────────────────────────────────
    def add_edge(self, u, v):
        self.adj[u
].append(v)
        if not self.directed:
            self.adj[v
].append(u)

    # ── O(degree) — Remove edge ──────────────────────────────────────────
    def remove_edge(self, u, v):
        self.adj[u
] = [n for n in self.adj[u
    ] if n != v
]
        if not self.directed:
            self.adj[v
] = [n for n in self.adj[v
    ] if n != u
]

    # ── O(degree) — Check if edge exists ────────────────────────────────
    def has_edge(self, u, v):
        return v in self.adj[u
]

    # ── O(1) — Get neighbors ─────────────────────────────────────────────
    def neighbors(self, v):
        return self.adj[v
]

    # ── O(V+E) — BFS ────────────────────────────────────────────────────
    def bfs(self, start):
        visited = {start
}
        queue   = deque([start
])   # deque for O(1) popleft
        order   = []
        while queue:
            curr = queue.popleft()
            order.append(curr)
            for neighbor in self.adj[curr
]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return order

    # ── O(V+E) — DFS (recursive) ────────────────────────────────────────
    def dfs(self, start, visited=None):
        if visited is None: visited = set()
        visited.add(start)
        order = [start
]
        for neighbor in self.adj[start
]:
            if neighbor not in visited:
                order.extend(self.dfs(neighbor, visited))
        return order

# Usage
g = Graph(directed=False)
for v in ['A','B','C','D','E'
]: g.add_vertex(v)
g.add_edge('A','B'); g.add_edge('A','C')
g.add_edge('B','D'); g.add_edge('C','E')

print(g.bfs('A'))        # ['A','B','C','D','E'
]
print(g.dfs('A'))        # ['A','B','D','C','E'
]
print(g.has_edge('A','B'))  # True
print(g.neighbors('A'))     # ['B','C'
]

 // ─── Graph in Java ──────────────────────────────────────────────────────────
//
// Adjacency list via HashMap<String, List<String>>.
// For weighted graphs, use HashMap<String, List<int[]>> where int[] = {neighbor, weight}.

import java.util.*;

public class Graph {
    private final Map<String, List<String>> adjList = new HashMap<>();
    private final boolean directed;

    public Graph(boolean directed) { this.directed = directed;
    }
    // ── O(1) — Add vertex ────────────────────────────────────────────────
    public void addVertex(String v) {
        adjList.putIfAbsent(v, new ArrayList<>());
    }
    // ── O(V+E) — Remove vertex + all edges ──────────────────────────────
    public void removeVertex(String v) {
        adjList.remove(v);
        for (List<String> neighbors : adjList.values())
            neighbors.remove(v);
    }
    // ── O(1) amortized — Add edge ─────────────────────────────────────────
    public void addEdge(String u, String v) {
        adjList.getOrDefault(u, Collections.emptyList()).add(v);
        if (!directed) adjList.getOrDefault(v, Collections.emptyList()).add(u);
    }
    // ── O(degree) — Remove edge ──────────────────────────────────────────
    public void removeEdge(String u, String v) {
        adjList.getOrDefault(u, Collections.emptyList()).remove(v);
        if (!directed) adjList.getOrDefault(v, Collections.emptyList()).remove(u);
    }
    // ── O(degree) — Has edge ─────────────────────────────────────────────
    public boolean hasEdge(String u, String v) {
        return adjList.getOrDefault(u, Collections.emptyList()).contains(v);
    }
    // ── O(1) — Get neighbors ──────────────────────────────────────────────
    public List<String> neighbors(String v) {
        return adjList.getOrDefault(v, Collections.emptyList());
    }
    // ── O(V+E) — BFS ──────────────────────────────────────────────────────
    public List<String> bfs(String start) {
        Set<String>    visited = new HashSet<>(Set.of(start));
        Queue<String>  queue   = new LinkedList<>(List.of(start));
        List<String>   order   = new ArrayList<>();

        while (!queue.isEmpty()) {
            String curr = queue.poll();
            order.add(curr);
            for (String neighbor : neighbors(curr)) {
                if (visited.add(neighbor)) // add returns true if not present
                    queue.offer(neighbor);
            }
        }
        return order;
    }
    // ── O(V+E) — DFS (iterative) ─────────────────────────────────────────
    public List<String> dfs(String start) {
        Set<String>    visited = new HashSet<>();
        Deque<String>  stack   = new ArrayDeque<>(List.of(start));
        List<String>   order   = new ArrayList<>();

        while (!stack.isEmpty()) {
            String curr = stack.pop();
            if (visited.contains(curr)) continue;
            visited.add(curr);
            order.add(curr);
            List<String> nbrs = new ArrayList<>(neighbors(curr));
            Collections.reverse(nbrs);
            for (String n : nbrs) if (!visited.contains(n)) stack.push(n);
        }
        return order;
    }
}

 // ─── Graph in C++ ───────────────────────────────────────────────────────────
//
// Adjacency list via unordered_map<string, vector<string>>.
// For weighted: unordered_map<string, vector<pair<string,int>>>.

#include <unordered_map>
#include <vector>
#include <string>
#include <queue>
#include <stack>
#include <unordered_set>
#include <algorithm>

class Graph {
    std::unordered_map<std::string, std::vector<std::string>> adj;
    bool directed;

public:
    Graph(bool directed = false) : directed(directed) {}
    // ── O(1) — Add vertex ────────────────────────────────────────────────
    void addVertex(const std::string& v) {
        adj.emplace(v, std::vector<std::string>{});
    }
    // ── O(V+E) — Remove vertex + all edges ──────────────────────────────
    void removeVertex(const std::string& v) {
        adj.erase(v);
        for (auto& [key, neighbors
        ] : adj) {
            neighbors.erase(std::remove(neighbors.begin(), neighbors.end(), v), neighbors.end());
        }
    }
    // ── O(1) amortized — Add edge ─────────────────────────────────────────
    void addEdge(const std::string& u, const std::string& v) {
        adj[u
        ].push_back(v);
        if (!directed) adj[v
        ].push_back(u);
    }
    // ── O(degree) — Remove edge ──────────────────────────────────────────
    void removeEdge(const std::string& u, const std::string& v) {
        auto& nu = adj[u
        ];
        nu.erase(std::remove(nu.begin(), nu.end(), v), nu.end());
        if (!directed) {
            auto& nv = adj[v
            ];
            nv.erase(std::remove(nv.begin(), nv.end(), u), nv.end());
        }
    }
    // ── O(degree) — Has edge ─────────────────────────────────────────────
    bool hasEdge(const std::string& u, const std::string& v) const {
        auto it = adj.find(u);
        if (it == adj.end()) return false;
        return std::find(it->second.begin(), it->second.end(), v) != it->second.end();
    }
    // ── O(1) — Get neighbors ──────────────────────────────────────────────
    const std::vector<std::string>& neighbors(const std::string& v) const {
        return adj.at(v);
    }
    // ── O(V+E) — BFS ──────────────────────────────────────────────────────
    std::vector<std::string> bfs(const std::string& start) const {
        std::unordered_set<std::string> visited = {start
        };
        std::queue<std::string>         q;
        std::vector<std::string>        order;
        q.push(start);
        while (!q.empty()) {
            auto curr = q.front(); q.pop();
            order.push_back(curr);
            for (const auto& n : adj.at(curr))
                if (visited.insert(n).second) q.push(n);
        }
        return order;
    }
    // ── O(V+E) — DFS (iterative) ─────────────────────────────────────────
    std::vector<std::string> dfs(const std::string& start) const {
        std::unordered_set<std::string> visited;
        std::stack<std::string>         s;
        std::vector<std::string>        order;
        s.push(start);
        while (!s.empty()) {
            auto curr = s.top(); s.pop();
            if (visited.count(curr)) continue;
            visited.insert(curr);
            order.push_back(curr);
            const auto& nbrs = adj.at(curr);
            for (auto it = nbrs.rbegin(); it != nbrs.rend(); ++it)
                if (!visited.count(*it)) s.push(*it);
        }
        return order;
    }
};
